import FixtureRow from './fixture-row';
import { Fixture } from '../../objects/fixture';

interface FixtureComponentProps{
    fixture : Fixture    
}
const SingleFixtureTable = (fixturesProps : FixtureComponentProps) => {      

    return(
        <>                       
        <div className="row">            
            <div>
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <th>Date</th>
                            <th>Result</th>
                            <th>Home Team</th>
                            <th></th>
                            <th></th>                                                                                                 
                            <th></th>  
                            <th>Away Team</th>  
                        </tr>
                    </thead>
                    <tbody>                        
                        <FixtureRow key={fixturesProps.fixture.id} fixture={fixturesProps.fixture} />
                    </tbody>
                </table>                          
            </div>
        </div>                
        </>
    );
}
export default SingleFixtureTable;
